  justify-content: center;
  background: var(--backdrop-overlay);
  backdrop-filter: blur(var(--backdrop-blur));
  -webkit-backdrop-filter: blur(var(--backdrop-blur));
  z-index: $z-alert;
  border-radius: $radius-window;
  animation: alert-backdrop-enter $transition-normal ease-out both;

  &--exiting {
    animation: alert-backdrop-exit $transition-normal ease-in both;
  }
}

.alert__dialog {
  display: flex;
  flex-direction: column;
  align-items: center;
  width: $alert-dialog-width;
  padding: $space-5 $space-4 $space-4;
  background: var(--color-surface);
  border: 1px solid var(--border-100);
  border-radius: $radius-lg;
  box-shadow: var(--shadow-popover);
  animation: alert-dialog-enter $transition-normal ease-out both;

  &--exiting {
    animation: alert-dialog-exit $transition-normal ease-in both;
  }
}

.alert__icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: $space-8;
  height: $space-8;
  margin-bottom: $space-3;
  color: var(--text-600);
}

.alert__title {
  margin: 0;
  font-size: $font-md;
  font-weight: $font-weight-semibold;
  color: var(--color-text-primary);
  text-align: center;
}

.alert__message {
  margin: $space-1 0 0;
  font-size: $font-sm;
  color: var(--text-600);
  text-align: center;
}

.alert__actions {
  display: flex;
  gap: $space-2;
  width: 100%;
  margin-top: $space-4;
}

.alert__button {
  flex: 1;
  height: $space-8;
  padding: 0 $space-3;
  border: none;
  border-radius: $radius-md;
  font-family: $font-family;
  font-size: $font-sm;
  font-weight: $font-weight-medium;
  cursor: pointer;
  transition: background-color $transition-fast ease;

  &--default {
    background: var(--color-accent);
    color: var(--color-text-on-accent);

    &:hover {
      background: var(--color-accent-hover);
    }
  }

  &--destructive {
    background: var(--color-destructive);
    color: var(--color-text-on-accent);

    &:hover {
      background: var(--color-destructive-hover);
    }
  }

  &--cancel {
    background: var(--border-100);
    color: var(--color-text-primary);

    &:hover {
      background: var(--border-200);
    }
  }

  &:focus-visible {
    outline: 2px solid var(--color-accent);
    outline-offset: -2px;
  }
}

@keyframes alert-backdrop-enter {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes alert-backdrop-exit {
  from {
    opacity: 1;
  }
  to {
    opacity: 0;
  }
}

@keyframes alert-dialog-enter {
  from {
    opacity: 0;
    transform: scale(0.95);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes alert-dialog-exit {
  from {
    opacity: 1;
    transform: scale(1);
  }
  to {
    opacity: 0;
    transform: scale(0.95);
  }
}

